/** @internal */
/**
 * Formats a byte count into a human-readable string.
 * @example formatBytes(2048) → "2.0 KB"
 */
export function formatBytes(bytes: number): string {
  if (bytes === 0) return '0 B';
  const units = ['B', 'KB', 'MB', 'GB'];
  const i = Math.floor(Math.log(bytes) / Math.log(1024));
  const value = bytes / 1024 ** i;
  return `${value.toFixed(value < 10 && i > 0 ? 1 : 0)} ${units[i]}`;
}

/**
 * Returns true if the given file matches the accept string.
 * Supports MIME types ("image/*", "application/pdf") and extensions (".pdf").
 */
export function fileMatchesAccept(file: File, accept: string): boolean {
  const parts = accept
    .split(',')
    .map(s => s.trim())
    .filter(Boolean);

  return parts.some(pattern => {
    if (pattern.startsWith('.')) {
      return file.name.toLowerCase().endsWith(pattern.toLowerCase());
    }
    if (pattern.endsWith('/*')) {
      return file.type.startsWith(pattern.slice(0, -1));
    }
    return file.type === pattern;
  });
}

/** Returns true if the file is an image (based on MIME type). */
export function isImageFile(file: File): boolean {
  return file.type.startsWith('image/');
}
